"use strict";(globalThis.webpackChunkcodeeatcode_github_io=globalThis.webpackChunkcodeeatcode_github_io||[]).push([[5972],{9735(e,t,n){n.r(t),n.d(t,{assets:()=>l,contentTitle:()=>o,default:()=>c,frontMatter:()=>i,metadata:()=>a,toc:()=>d});var a=n(9293),s=n(4848),r=n(8453);const i={title:"The Classic 'Works on My Machine' \u2014 Now With Neural Networks",slug:"the-classic-works-on-my-machine-now-with-neural-networks",date:new Date("2026-05-21T09:00:00.000Z"),last_updated:new Date("2026-05-21T12:00:00.000Z"),authors:["ambersariya"],tags:["ai-engineering","python","lessons-learned","document-parsing","testing"]},o=void 0,l={authorsImageUrls:[void 0]},d=[{value:"Why Document Fidelity Matters",id:"why-document-fidelity-matters",level:2},{value:"Starting Simple, Hitting Walls",id:"starting-simple-hitting-walls",level:2},{value:"Building the Evaluation Harness",id:"building-the-evaluation-harness",level:2},{value:"The Constraint We Didn&#39;t Measure",id:"the-constraint-we-didnt-measure",level:2},{value:"Pragmatism Over Purity",id:"pragmatism-over-purity",level:2},{value:"Now It&#39;s All Prompt-Driven",id:"now-its-all-prompt-driven",level:2},{value:"What the Evaluation Harness Gets Right \u2014 And What It Doesn&#39;t",id:"what-the-evaluation-harness-gets-right--and-what-it-doesnt",level:2},{value:"Lessons",id:"lessons",level:2}];function h(e){const t={a:"a",code:"code",em:"em",h2:"h2",li:"li",p:"p",strong:"strong",ul:"ul",...(0,r.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(t.p,{children:"There's a version of this story where we made a mistake and fixed it. That's true but incomplete. The fuller version is about what a structured evaluation process gets right, what it misses, and how the ground can shift under you even when you've done the work."}),"\n",(0,s.jsx)(t.h2,{id:"why-document-fidelity-matters",children:"Why Document Fidelity Matters"}),"\n",(0,s.jsx)(t.p,{children:"Our virtual assistant answers questions by retrieving content from product documentation \u2014 policies, guides, structured forms. For retrieval to produce accurate, grounded answers, the source material has to survive parsing intact."}),"\n",(0,s.jsx)(t.p,{children:"This sounds obvious until you see what \"not intact\" looks like in practice. A table rendered as a flat string of values with no row or column relationship. A heading that becomes a bold paragraph indistinguishable from body copy. A figure caption attached to nothing. These aren't cosmetic defects \u2014 they're retrieval failures. The model can't correctly reference what wasn't preserved."}),"\n",(0,s.jsx)(t.p,{children:"Our requirements were non-negotiable:"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsxs)(t.li,{children:[(0,s.jsx)(t.strong,{children:"Scanned and rasterised PDFs"})," \u2014 documents with no embedded text layer, relying entirely on OCR"]}),"\n",(0,s.jsxs)(t.li,{children:[(0,s.jsx)(t.strong,{children:"Table structure"})," \u2014 including merged cells, multi-row headers, nested content"]}),"\n",(0,s.jsxs)(t.li,{children:[(0,s.jsx)(t.strong,{children:"Layout and heading hierarchy"})," \u2014 sections, subsections, callouts, columns"]}),"\n",(0,s.jsxs)(t.li,{children:[(0,s.jsx)(t.strong,{children:"Image semantics"})," \u2014 figures and diagrams needed descriptions, not just placeholders"]}),"\n"]}),"\n",(0,s.jsx)(t.p,{children:"Without these, the knowledge base becomes a lossy approximation of the actual documents. RAG answers become confidently wrong."}),"\n",(0,s.jsx)(t.h2,{id:"starting-simple-hitting-walls",children:"Starting Simple, Hitting Walls"}),"\n",(0,s.jsxs)(t.p,{children:["We started where most teams start: the obvious libraries. ",(0,s.jsx)(t.code,{children:"python-docx"})," for Word documents, ",(0,s.jsx)(t.code,{children:"pdfplumber"}),", ",(0,s.jsx)(t.code,{children:"pypdf"}),", and ",(0,s.jsx)(t.code,{children:"PyMuPDF"})," for PDFs. These are excellent tools \u2014 fast, lightweight, well-maintained, and more than capable for clean digital documents."]}),"\n",(0,s.jsx)(t.p,{children:"Our documents weren't clean. The simpler libraries handled native digital PDFs without trouble but broke down on scanned content and gave up entirely on complex table structures. Merged cells became misaligned rows. Headings lost their hierarchy. OCR was absent or rudimentary."}),"\n",(0,s.jsx)(t.p,{children:"We needed to go deeper."}),"\n",(0,s.jsx)(t.h2,{id:"building-the-evaluation-harness",children:"Building the Evaluation Harness"}),"\n",(0,s.jsxs)(t.p,{children:["Rather than try libraries one at a time, we built a structured comparison harness \u2014 ",(0,s.jsx)(t.a,{href:"https://github.com/ambersariya/pdf-parsing-comparison",children:"available here"})," if you want to run it yourself. Ten parsers, standardised document inputs representing the range of formats we'd encounter in production, and a consistent set of metrics:"]}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:"Wall-clock parse time"}),"\n",(0,s.jsx)(t.li,{children:"Peak memory consumption"}),"\n",(0,s.jsx)(t.li,{children:"Word count accuracy (proxy for text extraction fidelity)"}),"\n",(0,s.jsx)(t.li,{children:"Table detection and structure preservation"}),"\n",(0,s.jsx)(t.li,{children:"Heading and layout extraction quality"}),"\n"]}),"\n",(0,s.jsx)(t.p,{children:"The harness made evaluation repeatable and honest. We ran everything through the same documents, measured the same things, and scored against the same rubric."}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Docling won on every qualitative dimension that mattered."})," It produced structured, readable Markdown that actually reflected the document's intent \u2014 tables with correct cell relationships, headings with correct hierarchy, image descriptions, and full OCR support for scanned content. For our requirements, it wasn't close."]}),"\n",(0,s.jsx)(t.p,{children:"We shipped it."}),"\n",(0,s.jsx)(t.h2,{id:"the-constraint-we-didnt-measure",children:"The Constraint We Didn't Measure"}),"\n",(0,s.jsx)(t.p,{children:"Here is where the story gets instructive."}),"\n",(0,s.jsx)(t.p,{children:"Docling is not a lightweight parser. It's a neural network pipeline: layout detection models, table structure analysis, OCR, and PyTorch inference \u2014 all running locally, inside the pod, on every document processed."}),"\n",(0,s.jsx)(t.p,{children:"We had evaluated it on an M4 Pro MacBook with Apple Silicon MPS acceleration. Near-GPU performance for PyTorch workloads. Parse times of two to three seconds per document."}),"\n",(0,s.jsx)(t.p,{children:"Production was CPU-only Kubernetes nodes."}),"\n",(0,s.jsx)(t.p,{children:"The performance gap was not a percentage difference. It was an order of magnitude. What took seconds on the MacBook took minutes on a CPU pod. Our AWS load balancer had a 60-second timeout. Docling on CPU regularly exceeded that."}),"\n",(0,s.jsxs)(t.p,{children:["The consequence: timeouts, 502 errors, retry storms, queue backlog, pod memory pressure. Five weeks of thread throttling, semaphore tuning, and concurrency experiments \u2014 the full story is in the ",(0,s.jsx)(t.a,{href:"/we-spent-five-weeks-making-docling-work-then-we-deleted-it/",children:"Docling post-mortem"}),". The constraint was never the code. It was the hardware, and we had benchmarked against hardware we didn't have in production."]}),"\n",(0,s.jsx)(t.p,{children:"There's a human element worth naming too. We were under pressure to find a solution that met those qualitative requirements, and Docling met them convincingly. When you're looking for something specific and you find it, the instinct is to commit \u2014 not to ask what happens when you move it to a different machine. That instinct is understandable. It's also exactly when the infrastructure question matters most."}),"\n",(0,s.jsxs)(t.p,{children:["The harness was rigorous. The question it was missing: ",(0,s.jsx)(t.em,{children:"does this library assume hardware you don't have?"})]}),"\n",(0,s.jsx)(t.h2,{id:"pragmatism-over-purity",children:"Pragmatism Over Purity"}),"\n",(0,s.jsx)(t.p,{children:'At some point the engineering question stopped being "how do we make Docling work on CPU" and became "why does it have to run locally at all?"'}),"\n",(0,s.jsx)(t.p,{children:"We could have chased GPU nodes. We could have built an async queue and worked around the timeout with a callback model. We could have kept tuning. Any of those would have been defensible."}),"\n",(0,s.jsx)(t.p,{children:"Instead we stepped back. The requirement was structured, semantically meaningful content extracted from documents. That's a capability problem, not an infrastructure problem. The assumption that it needed to be solved with local inference was an artefact of the evaluation process, not a genuine constraint."}),"\n",(0,s.jsx)(t.h2,{id:"now-its-all-prompt-driven",children:"Now It's All Prompt-Driven"}),"\n",(0,s.jsx)(t.p,{children:"Claude via Bedrock handles our complete requirements \u2014 scanned PDFs, merged-cell tables, layout hierarchy, image semantics \u2014 without a byte of local inference."}),"\n",(0,s.jsx)(t.p,{children:"The implementation is straightforward. For documents under 4.5MB we send a document block directly to the Bedrock API. For larger documents, we rasterise each page to PNG and send image blocks. Claude returns structured Markdown that preserves the document's intent."}),"\n",(0,s.jsx)(t.p,{children:'Pod CPU stays flat during parsing. No timeouts. No GPU nodes. No async queue. No concurrency tuning. The "parsing pipeline" is a well-prompted API call.'}),"\n",(0,s.jsx)(t.p,{children:"The accuracy is comparable to Docling on our document set. The operational complexity is dramatically lower."}),"\n",(0,s.jsx)(t.h2,{id:"what-the-evaluation-harness-gets-right--and-what-it-doesnt",children:"What the Evaluation Harness Gets Right \u2014 And What It Doesn't"}),"\n",(0,s.jsx)(t.p,{children:"The structured evaluation process had real value. It forced rigour where gut feel would have been faster but less reliable. The harness surfaced Docling as the correct answer to the qualitative question we were asking."}),"\n",(0,s.jsx)(t.p,{children:"The gap was in the question itself. We measured capability and performance, but performance on the wrong hardware. For any library that runs local inference \u2014 ML models, neural networks, GPU-accelerated workloads \u2014 production hardware parity is not an optional benchmark condition. It's the first one."}),"\n",(0,s.jsx)(t.p,{children:'There\'s also a broader point about evaluation framing. The harness asked "which library does this best?" It didn\'t ask "should this be a library at all?" As LLM APIs have matured, the answer to a class of document understanding problems has shifted from "find the best local model" to "describe what you need and ask a capable model." The evaluation dimension that matters now isn\'t which OCR pipeline is most accurate \u2014 it\'s whether the capability can be prompt-driven and whether that changes your operational posture.'}),"\n",(0,s.jsx)(t.p,{children:"For us it did, substantially."}),"\n",(0,s.jsx)(t.h2,{id:"lessons",children:"Lessons"}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"1. Hardware parity is line one of the evaluation checklist for ML-heavy libraries."}),"\nBenchmarking on an M4 Pro and deploying to CPU Kubernetes is not a benchmark. It's a misdirection. Add production-equivalent hardware to the evaluation environment before architectural commitment."]}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"2. Structured evaluation is worth building \u2014 but the harness only finds what you measure."}),'\nThe comparison harness was the right approach. We just needed one more measurement axis: "does this work on the hardware we actually have?"']}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"3. Pragmatism beats purity."}),"\nWe could have made Docling work in production. The question was whether the cost \u2014 GPU nodes, async queues, operational complexity \u2014 was proportionate to the benefit over an API-based alternative. It wasn't."]}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"4. The right abstraction level has shifted."}),'\nA year ago the answer to "parse this complex PDF" was "find the best parser library." Today it\'s often "send it to a VLM." The evaluation harness needs to include that option, and the question needs to be capability-first rather than implementation-first.']}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"5. Five weeks is feedback, not failure."}),"\nThe operational pain of running Docling in production gave us the forcing function to reconsider the approach. Teams that avoid the pain by over-engineering around it (GPU nodes, larger instances, longer timeouts) often miss the signal."]})]})}function c(e={}){const{wrapper:t}={...(0,r.R)(),...e.components};return t?(0,s.jsx)(t,{...e,children:(0,s.jsx)(h,{...e})}):h(e)}},8453(e,t,n){n.d(t,{R:()=>i,x:()=>o});var a=n(6540);const s={},r=a.createContext(s);function i(e){const t=a.useContext(r);return a.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function o(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:i(e.components),a.createElement(r.Provider,{value:t},e.children)}},9293(e){e.exports=JSON.parse('{"permalink":"/the-classic-works-on-my-machine-now-with-neural-networks","source":"@site/blog/The Classic Works on My Machine Now With Neural Networks.md","title":"The Classic \'Works on My Machine\' \u2014 Now With Neural Networks","description":"There\'s a version of this story where we made a mistake and fixed it. That\'s true but incomplete. The fuller version is about what a structured evaluation process gets right, what it misses, and how the ground can shift under you even when you\'ve done the work.","date":"2026-05-21T09:00:00.000Z","tags":[{"inline":true,"label":"ai-engineering","permalink":"/tags/ai-engineering"},{"inline":true,"label":"python","permalink":"/tags/python"},{"inline":true,"label":"lessons-learned","permalink":"/tags/lessons-learned"},{"inline":true,"label":"document-parsing","permalink":"/tags/document-parsing"},{"inline":true,"label":"testing","permalink":"/tags/testing"}],"readingTime":6.58,"hasTruncateMarker":true,"authors":[{"name":"Danish Javed","title":"Software Engineer","url":"https://github.com/ambersariya","imageURL":"https://avatars.githubusercontent.com/u/1080238?s=400&u=5d6212c54765773934d34b3e55908846c9cd4a42&v=4","key":"ambersariya","page":null}],"frontMatter":{"title":"The Classic \'Works on My Machine\' \u2014 Now With Neural Networks","slug":"the-classic-works-on-my-machine-now-with-neural-networks","date":"2026-05-21T09:00:00.000Z","last_updated":"2026-05-21T12:00:00.000Z","authors":["ambersariya"],"tags":["ai-engineering","python","lessons-learned","document-parsing","testing"]},"unlisted":false,"nextItem":{"title":"We Spent Five Weeks Making Docling Work. Then We Deleted It.","permalink":"/we-spent-five-weeks-making-docling-work-then-we-deleted-it"}}')}}]);